VALUES ('AR-MED-MAL-STANDARD-OF-CARE', 5, 'AR Medical Malpractice: Standard of Care (Ark. Code § 16-114-206)', 'content_check', 'personal_injury', 'medical_malpractice', 'complaint', 'state', 'AR',
    jsonb_build_object('sub_specialization_type', 'medical_malpractice', 'authority_level', 'contextual_rule', 'statute', 'Ark. Code § 16-114-206', 'standard_text', 'A medical care provider shall exercise that degree of care, skill, and treatment which, in light of all relevant surrounding circumstances, is recognized as acceptable and appropriate by reasonably careful, qualified medical care providers in the same field', 'key_elements', jsonb_build_array('Duty: provider-patient relationship established', 'Breach: failure to meet the applicable standard of care', 'Causation: breach was proximate cause of plaintiff injury', 'Damages: compensable harm resulted'), 'national_standard', 'Arkansas moved away from strict locality rule to a national/reasonably prudent provider standard', 'res_ipsa', 'Available where the negligence is of a type that a layperson can recognize without expert testimony', 'informed_consent', 'Separate theory under Ark. Code § 16-114-206(b): provider must disclose risks that a reasonably prudent patient would consider material', 'hospital_liability', 'Hospitals may be held vicariously liable for physicians under agency or ostensible agency theories', 'verification', jsonb_build_object('statute_verified', true, 'sources', jsonb_build_array('Ark. Code § 16-114-206', 'Arkansas Medical Malpractice Act', 'Justia — Arkansas Medical Injury'), 'confidence', 'high')),
